  function ensureDwfConfirm() {
    var $mask = $('#dwf-confirm-mask');
    if ($mask.length) return $mask;
    $mask = $(
      '<div class="dwf-confirm-mask" id="dwf-confirm-mask" role="dialog" aria-modal="true" aria-labelledby="dwf-confirm-title" tabindex="-1">' +
        '<div class="dwf-confirm-box">' +
          '<div class="dwf-confirm-head">' +
            '<div class="dwf-confirm-icon"><i class="fa-solid fa-triangle-exclamation"></i></div>' +
            '<div class="dwf-confirm-title" id="dwf-confirm-title"></div>' +
          '</div>' +
          '<div class="dwf-confirm-body" id="dwf-confirm-body"></div>' +
          '<div class="dwf-confirm-actions">' +
            '<button type="button" class="dwf-confirm-btn" data-dwf-confirm-cancel="1">取消</button>' +
            '<button type="button" class="dwf-confirm-btn danger" data-dwf-confirm-ok="1">确认放弃</button>' +
          '</div>' +
        '</div>' +
      '</div>',
    );
    $('body').append($mask);
    return $mask;
  }

  function showDwfConfirm(opts) {
    opts = opts || {};
    var $mask = ensureDwfConfirm();
    $('#dwf-confirm-title').text(opts.title || '确认操作');
    $('#dwf-confirm-body').html(opts.body || '');
    $mask.find('[data-dwf-confirm-ok]').text(opts.okText || '确认');
    $mask.addClass('show').css('display', 'flex');
    try {
      $mask.trigger('focus');
    } catch (e) {}
    return new Promise(function (resolve) {
      function close(result) {
        $(document).off('keydown.dwfConfirm');
        $mask.off('click.dwfConfirm');
        $mask.removeClass('show').hide();
        resolve(result);
      }
      $mask.on('click.dwfConfirm', function (e) {
        if (e.target === $mask.get(0) || $(e.target).closest('[data-dwf-confirm-cancel]').length) close(false);
        if ($(e.target).closest('[data-dwf-confirm-ok]').length) close(true);
      });
      $(document).on('keydown.dwfConfirm', function (e) {
        if (e.key === 'Escape') close(false);
      });
    });
  }

  function resolveTavernApi(name) {
    var roots = [global];
    try {
      if (global.parent && global.parent !== global) roots.push(global.parent);
    } catch (e) {}
    for (var i = 0; i < roots.length; i += 1) {
      var root = roots[i];
      if (root && typeof root[name] === 'function') return root[name].bind(root);
    }
    return null;
  }

  function resolveMvuApi() {
    return global.Mvu || (global.parent && global.parent.Mvu) || null;
  }

  /** KB: message_id = getCurrentMessageId() */
  function resolveMvuMessageId() {
    var getCurrentMessageId = resolveTavernApi('getCurrentMessageId');
    if (!getCurrentMessageId) return null;
    try {
      var id = getCurrentMessageId();
      if (id != null && id !== '' && !isNaN(id)) return Number(id);
    } catch (e) {}
    return null;
  }

  function getMvuMessageOption() {
    var messageId = resolveMvuMessageId();
    if (messageId == null) return null;
    return { type: 'message', message_id: messageId };
  }

  function parseStatData(raw) {
    if (global.__DWF_PREVIEW_BOOT__) {
      return raw && typeof raw === 'object' ? cloneData(raw) : {};
    }
    var Schema = global.__DWF_STAT_SCHEMA__;
    if (!Schema || typeof Schema.parse !== 'function') {
      console.warn('[大魏芳华:UI] Stat Schema 不可用，无法 parse stat_data');
      return {};
    }
    try {
      return Schema.parse(raw == null ? {} : raw, { reportInput: true });
    } catch (e) {
      console.warn('[大魏芳华:UI] Schema.parse 失败', e);
      global.__DWF_STAT_PARSE_FAILED__ = true;
      return null;
    }
  }

  function normalizeStatDataForWrite(raw) {
    if (global.__DWF_PREVIEW_BOOT__) {
      return raw && typeof raw === 'object' ? cloneData(raw) : {};
    }
    var Schema = global.__DWF_STAT_SCHEMA__;
    if (!Schema || typeof Schema.parse !== 'function') return null;
    try {
      return Schema.parse(raw == null ? {} : raw, { reportInput: true });
    } catch (e) {
      console.warn('[大魏芳华:UI] 写入前 Schema.parse 失败，已阻止 MVU 写入', e);
      return null;
    }
  }

  function readPreviewSessionItem(key) {
    try {
      var local = sessionStorage.getItem(key);
      if (local != null && local !== '') return local;
    } catch (e) {}
    try {
      if (global.parent && global.parent !== global) {
        var parentVal = global.parent.sessionStorage.getItem(key);
        if (parentVal != null && parentVal !== '') return parentVal;
      }
    } catch (e) {}
    return null;
  }

  function writePreviewSessionItem(key, value) {
    try {
      sessionStorage.setItem(key, value);
    } catch (e) {}
    try {
      if (global.parent && global.parent !== global) {
        global.parent.sessionStorage.setItem(key, value);
      }
    } catch (e) {}
  }

  function readPreviewStatObject() {
    try {
      var raw = readPreviewSessionItem('__dwf_preview_stat__');
      if (raw) {
        var parsed = JSON.parse(raw);
        if (parsed && typeof parsed === 'object') return parsed;
      }
    } catch (e) {}
    if (__dwfLastGoodStat && typeof __dwfLastGoodStat === 'object') {
      return cloneData(__dwfLastGoodStat);
    }
    if (global.__DWF_PREVIEW_STAT__ && typeof global.__DWF_PREVIEW_STAT__ === 'object') {
      return cloneData(global.__DWF_PREVIEW_STAT__);
    }
    return null;
  }

  function getStatData(options) {
    options = options || {};
    if (global.__DWF_PREVIEW_BOOT__) {
      var previewStat = readPreviewStatObject();
      if (previewStat) {
        __dwfLastGoodStat = previewStat;
        global.__DWF_STAT_PARSE_FAILED__ = false;
        return options.clone ? cloneData(previewStat) : previewStat;
      }
    }
    if (global.__DWF_PREVIEW_STAT__ && typeof global.__DWF_PREVIEW_STAT__ === 'object') {
      __dwfLastGoodStat = global.__DWF_PREVIEW_STAT__;
      return options.clone ? cloneData(global.__DWF_PREVIEW_STAT__) : global.__DWF_PREVIEW_STAT__;
    }
    var MvuApi = resolveMvuApi();
    var opt = getMvuMessageOption();
    if (!MvuApi || !opt || typeof MvuApi.getMvuData !== 'function') {
      return __dwfLastGoodStat ? (options.clone ? cloneData(__dwfLastGoodStat) : __dwfLastGoodStat) : {};
    }
    try {
      var mvuData = MvuApi.getMvuData(opt) || {};
      var rawStat = _.get(mvuData, 'stat_data', {});
      var rawFp = mvuRawFingerprint(rawStat);
      var cacheKey = statCacheMessageKey(opt) + '@' + rawFp;
      if (
        !options.fresh &&
        __dwfStatCache.key === cacheKey &&
        __dwfStatCache.stat &&
        __dwfStatCache.rawFp === rawFp
      ) {
        return options.clone ? cloneData(__dwfStatCache.stat) : __dwfStatCache.stat;
      }
      var parsed = parseStatData(rawStat);
      if (parsed == null) {
        return __dwfLastGoodStat ? (options.clone ? cloneData(__dwfLastGoodStat) : __dwfLastGoodStat) : {};
      }
      __dwfStatCache = { key: cacheKey, stat: parsed, rawFp: rawFp };
      __dwfLastGoodStat = parsed;
      global.__DWF_STAT_PARSE_FAILED__ = false;
      return options.clone ? cloneData(parsed) : parsed;
    } catch (e) {
      return __dwfLastGoodStat ? (options.clone ? cloneData(__dwfLastGoodStat) : __dwfLastGoodStat) : {};
    }
  }

  function loadStatSchemaScript() {
    if (global.__DWF_STAT_SCHEMA__) return Promise.resolve(true);
    if (global.__dwfStatSchemaLoading) return global.__dwfStatSchemaLoading;
    global.__dwfStatSchemaLoading = new Promise(function (resolve) {
      if (global.__DWF_STAT_SCHEMA__) {
        resolve(true);
        return;
      }
      var script = document.createElement('script');
      script.src = dwfStatusAsset('dwf-stat-schema.js');
      script.onload = function () {
        resolve(!!global.__DWF_STAT_SCHEMA__);
      };
      script.onerror = function () {
        console.warn('[大魏芳华:UI] 加载 dwf-stat-schema.js 失败');
        resolve(false);
      };
      document.head.appendChild(script);
    });
    return global.__dwfStatSchemaLoading;
  }

  async function ensureZodGlobal() {
    if (global.__DWF_PREVIEW_BOOT__ || global.z) return true;
    if (global.__dwfZodLoading) return global.__dwfZodLoading;
    global.__dwfZodLoading = (async function () {
      try {
        var dynamicImport = new Function('url', 'return import(url);');
        var mod = await dynamicImport(ZOD_MODULE_URL);
        if (!global.z) global.z = mod.z || (mod.default && mod.default.z) || mod.default || mod;
        if (!global.z || typeof global.z.object !== 'function') return false;
        if (typeof global.z.object({}).prefault !== 'function') {
          console.warn('[大魏芳华:UI] zod 缺少 prefault，请使用 mvu_zod');
          return false;
        }
        return true;
      } catch (e) {
        console.warn('[大魏芳华:UI] 加载 zod 失败，无法启用 Stat Schema', e);
        return false;
      }
    })();
    return global.__dwfZodLoading;
  }

  async function ensureStatSchema() {
    if (global.__DWF_PREVIEW_BOOT__) return true;
    var zReady = await ensureZodGlobal();
    if (!zReady) return false;
    return loadStatSchemaScript();
  }

  async function ensureWaitUntil() {
    if (global.__DWF_PREVIEW_BOOT__ || typeof global.__dwfWaitUntil === 'function') return true;
    if (global.__dwfWaitUntilLoading) return global.__dwfWaitUntilLoading;
    global.__dwfWaitUntilLoading = (async function () {
      try {
        var dynamicImport = new Function('url', 'return import(url);');
        var mod = await dynamicImport(WAIT_UNTIL_MODULE_URL);
        global.__dwfWaitUntil = mod.waitUntil || (mod.default && mod.default.waitUntil) || mod.default || mod;
        return typeof global.__dwfWaitUntil === 'function';
      } catch (e) {
        console.warn('[大魏芳华:UI] 加载 waitUntil 失败', e);
        return false;
      }
    })();
    return global.__dwfWaitUntilLoading;
  }

  function messageHasStatData() {
    var MvuApi = resolveMvuApi();
    var opt = getMvuMessageOption();
    if (MvuApi && typeof MvuApi.getMvuData === 'function') {
      try {
        var mvuData = MvuApi.getMvuData(opt || { type: 'message' }) || {};
        if (_.has(mvuData, 'stat_data')) return true;
      } catch (e) {}
    }
    var getVariables = resolveTavernApi('getVariables');
    if (!getVariables) return false;
    try {
      if (opt && _.has(getVariables(opt), 'stat_data')) return true;
      return _.has(getVariables({ type: 'message' }), 'stat_data');
    } catch (e) {}
    return false;
  }

  /** KB: await waitUntil(() => _.has(getVariables({ type: 'message' }), 'stat_data')) */
  async function waitForMessageStatData() {
    if (global.__DWF_PREVIEW_BOOT__) return true;
    if (!(await ensureWaitUntil())) {
      console.warn('[大魏芳华:UI] waitUntil 不可用');
      return false;
    }
    var getVariables = resolveTavernApi('getVariables');
    var waitUntil = global.__dwfWaitUntil;
    if (!getVariables || typeof waitUntil !== 'function') {
      console.warn('[大魏芳华:UI] getVariables 或 waitUntil 不可用');
      return false;
    }
    try {
      await waitUntil(
        function () {
          return messageHasStatData();
        },
        { timeout: 60000, intervalBetweenAttempts: 50 },
      );
      return true;
    } catch (e) {
      console.warn('[大魏芳华:UI] 等待消息楼层 stat_data 超时', e);
      return false;
    }
  }

  async function persistMvuPatch(patchFn) {
    if (typeof patchFn !== 'function') return false;
    if (global.__DWF_PREVIEW_BOOT__) {
      var previewWrapper = { stat_data: cloneData(getStatData({ clone: true })) };
      normalizeCurrentTasksOnMvu(previewWrapper);
      if (patchFn(previewWrapper) === false) return false;
      var previewStat = previewWrapper.stat_data;
      try {
        writePreviewSessionItem('__dwf_preview_stat__', JSON.stringify(previewStat));
      } catch (e) {}
      global.__DWF_PREVIEW_STAT__ = previewStat;
      invalidateMvuReadCaches();
      __dwfLastGoodStat = previewStat;
      __dwfStatCache = { key: 'preview', stat: previewStat, rawFp: mvuRawFingerprint(previewStat) };
      renderDwfSubPanels(previewStat, { force: true });
      return true;
    }
    var MvuApi = resolveMvuApi();
    var opt = getMvuMessageOption();
    if (!MvuApi || !opt || typeof MvuApi.getMvuData !== 'function' || typeof MvuApi.replaceMvuData !== 'function') {
      console.warn('[大魏芳华:UI] Mvu 不可用');
      return false;
    }
    try {
      if (!(await ensureStatSchema())) return false;
      var mvuData = cloneData(MvuApi.getMvuData(opt) || {});
      if (!_.has(mvuData, 'stat_data')) _.set(mvuData, 'stat_data', {});
      if (patchFn(mvuData) === false) return false;
      var normalizedStat = normalizeStatDataForWrite(_.get(mvuData, 'stat_data', {}));
      if (!normalizedStat) return false;
      _.set(mvuData, 'stat_data', normalizedStat);
      await MvuApi.replaceMvuData(mvuData, opt);
      invalidateMvuReadCaches();
      var freshMvu = MvuApi.getMvuData(opt) || {};
      var freshStat = parseStatData(_.get(freshMvu, 'stat_data', {}));
      if (freshStat != null) {
        __dwfLastGoodStat = freshStat;
        __dwfStatCache = {
          key: statCacheMessageKey(opt) + '@' + mvuRawFingerprint(_.get(freshMvu, 'stat_data', {})),
          stat: freshStat,
          rawFp: mvuRawFingerprint(_.get(freshMvu, 'stat_data', {})),
        };
        global.__DWF_STAT_PARSE_FAILED__ = false;
      }
      renderDwfSubPanels(
        freshStat == null ? (__dwfLastGoodStat || {}) : freshStat,
        { force: true },
      );
      return true;
    } catch (e) {
      console.warn('[大魏芳华:UI] 写入 MVU 失败', e);
      return false;
    }
  }

  function invalidateJiyiCache() {
    __jiyiCacheKey = '';
    __jiyiCacheRows = null;
  }

  async function acceptJiyiTask(bucket, id) {
    return persistMvuPatch(function (mvuData) {
      normalizeCurrentTasksOnMvu(mvuData);
      var stat = _.get(mvuData, 'stat_data', {});
      if (taskAcceptBlockReason(stat, bucket)) return false;
      if (taskWasAbandoned(stat, id)) return false;
      if (hasCurrentTask(stat, id)) return false;
      var item = safeObj(_.get(stat, ['风闻录', '机宜', bucket, id]));
      if (!item['因由']) item = safeObj(_.get(computeJiyiFromCatalog(stat), [bucket, id]));
      if (!item['因由']) item = safeObj(findCatalogEvent(bucket, id));
      if (!id || !item['因由']) return false;
      _.set(mvuData, ['stat_data', '任务录', '当前', id], {
        id: id,
        类型: bucket,
        状态: '进行中',
        开始行程: Number(_.get(stat, '世界与剧情.行程', 1)) || 1,
        截止行程: Number(item['截止行程']) || 288,
        因由: item['因由'] || '',
        火急: item['火急'] || 2,
        相关人物: item['相关人物'] || '',
        建议地点: item['建议地点'] || '',
        目标: normalizeTaskGoals(item['目标'], item['选项']),
        演完写入: safeObj(item['演完写入']),
        错过策略: item['错过策略'] || '',
        错过写入: safeObj(item['错过写入']),
      });
      _.unset(mvuData, ['stat_data', '风闻录', '机宜', bucket, id]);
      return true;
    });
  }

  async function completeCurrentTask(id) {
    return persistMvuPatch(function (mvuData) {
      normalizeCurrentTasksOnMvu(mvuData);
      var stat = _.get(mvuData, 'stat_data', {});
      var task = getCurrentTask(stat, id);
      if (!taskCanComplete(stat, id)) return false;
      var history = safeObj(stat['履历']);
      var historyKey = nextHistoryKey(history);
      _.set(mvuData, 'stat_data.履历.' + historyKey, formatLvliRecord(stat, task.id));
      applyTaskDoneWritesMvu(mvuData, task['演完写入']);
      removeCurrentTaskOnMvu(mvuData, task.id);
      return true;
    });
  }

  async function clearFailedTask(id) {
    return persistMvuPatch(function (mvuData) {
      normalizeCurrentTasksOnMvu(mvuData);
      var stat = _.get(mvuData, 'stat_data', {});
      var task = getCurrentTask(stat, id);
      if (!task.id || !taskIsFailed(stat, id)) return false;
      removeCurrentTaskOnMvu(mvuData, task.id);
      return true;
    });
  }

  async function abandonCurrentTask(id) {
    return persistMvuPatch(function (mvuData) {
      normalizeCurrentTasksOnMvu(mvuData);
      var stat = _.get(mvuData, 'stat_data', {});
      var task = getCurrentTask(stat, id);
      if (!task.id || task['状态'] === '已失败' || taskIsExpired(stat, id)) return false;
      _.set(mvuData, ['stat_data', '任务录', '已放弃', task.id], {
        行程: Number(_.get(stat, '世界与剧情.行程', 1)) || 1,
        因由: task['因由'] || task.id,
      });
      removeCurrentTaskOnMvu(mvuData, task.id);
      return true;
    });
  }

  function formatLvliRecord(stat, deed) {
    var world = (stat && stat['世界与剧情']) || {};
    var tianshi = world['天时'] || {};
    var when = String(tianshi['显示'] || formatDisplayTime(stat) || '').replace(/·/g, '');
    var where = String(formatDisplayLocation(stat) || '').replace(/·/g, '');
    return when + '·' + where + '·' + String(deed || '').trim();
  }

  function parseLvliEntry(raw) {
    var s = String(raw || '').trim();
    if (!s) return { when: '', where: '', deed: '' };
    var parts = s
      .split('·')
      .map(function (p) {
        return p.trim();
      })
      .filter(Boolean);
    if (parts.length >= 3) {
      return {
        when: parts[0],
        where: parts.slice(1, -1).join('·'),
        deed: parts[parts.length - 1],
      };
    }
    if (parts.length === 2) {
      return { when: parts[0], where: '', deed: parts[1] };
    }
    return { when: '', where: '', deed: s };
  }

  function renderLvliCard(seq, raw) {
    var parsed = parseLvliEntry(raw);
    var deedText = resolveLvliDeedText(parsed, raw);
    var meta = [];
    if (parsed.when) meta.push('<span class="dwf-lvli-when">' + esc(parsed.when) + '</span>');
    if (parsed.where) meta.push('<span class="dwf-lvli-where"><i class="fa-solid fa-location-dot"></i>' + esc(parsed.where) + '</span>');
    return (
      '<article class="dwf-lvli-card dwf-lvli-card--compact dwf-glass-card">' +
      '<div class="dwf-lvli-rail"><span class="dwf-lvli-seq">' +
      esc(String(seq)) +
      '</span></div>' +
      '<div class="dwf-lvli-body">' +
      '<div class="dwf-lvli-line">' +
      (meta.length ? '<div class="dwf-lvli-meta">' + meta.join('') + '</div>' : '') +
      '<div class="dwf-lvli-deed">' +
      esc(deedText) +
      '</div></div>' +
      '</div></article>'
    );
  }
  function formatJiyiRemainText(remain) {
    if (remain <= 0) return '已是最后机会，再拖便错过';
    if (remain === 1) return '再拖一步便错过';
    return '再拖 ' + remain + ' 步便错过';
  }

  function resolveUserDisplayName() {
    var candidates = [];
    try {
      if (typeof global.name1 === 'string') candidates.push(global.name1);
    } catch (e) {}
    try {
      if (global.SillyTavern && global.SillyTavern.name1) candidates.push(global.SillyTavern.name1);
    } catch (e) {}
    try {
      if (global.parent && global.parent !== global) {
        if (typeof global.parent.name1 === 'string') candidates.push(global.parent.name1);
        if (global.parent.SillyTavern && global.parent.SillyTavern.name1) {
          candidates.push(global.parent.SillyTavern.name1);
        }
      }
    } catch (e) {}
    for (var i = 0; i < candidates.length; i++) {
      var n = String(candidates[i] || '').trim();
      if (n && n !== '{{user}}' && n !== '<user>') return n;
    }
    return '你';
  }

  function renderMoonRing(yueke) {
    var max = 288;
    var cur = Math.max(0, Math.min(max, Number(yueke) || 0));
    var pct = cur / max;
    var r = 36;
    var c = 2 * Math.PI * r;
    var off = c * (1 - pct);
    return (
      '<div class="dwf-moon-ring" aria-label="故事已推进 ' +
      cur +
      ' 步">' +
      '<svg viewBox="0 0 88 88" aria-hidden="true">' +
      '<defs><linearGradient id="dwfMoonGrad" x1="0%" y1="0%" x2="100%" y2="0%">' +
      '<stop offset="0%" stop-color="#b89465"/><stop offset="100%" stop-color="#e85d6a"/>' +
      '</linearGradient></defs>' +
      '<circle class="dwf-moon-track" cx="44" cy="44" r="' +
      r +
      '"/>' +
      '<circle class="dwf-moon-fill" cx="44" cy="44" r="' +
      r +
      '" stroke-dasharray="' +
      c +
      '" stroke-dashoffset="' +
      off +
      '"/>' +
      '</svg>' +
      '<div class="dwf-moon-core"><span class="dwf-moon-num">' +
      cur +
      '</span><span class="dwf-moon-lab">步</span></div></div>'
    );
  }

